async (params, browser) => {
  // Open ESPN scoreboard
  await browser.open(`https://www.espn.com/${params.sport}/scoreboard`)

  // Wait for scoreboard
  await browser.waitForSelector('[class*=\'Scoreboard\'], [class*=\'scoreboard\'], section, .content', 15000)

  // Let scores render
  await browser.wait(3000)

  // Scroll to load more games
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract scores
  const result = await browser.evaluate(`const games = []; document.querySelectorAll('[class*="Scoreboard"], [class*="scoreboard"], section[class*="ScoreboardPage"] > div, [class*="ScoreboardScoreCell"]').forEach((el, i) => { if (i < 15) { const teams = []; el.querySelectorAll('[class*="TeamName"], .team-name, [class*="truncate"], [class*="ScoreCell__TeamName"]').forEach(t => teams.push(t.textContent?.trim())); const scores = []; el.querySelectorAll('[class*="ScoreCell__Score"], [class*="Score"], .score').forEach(s => { const text = s.textContent?.trim(); if (text && /^\d+$/.test(text)) scores.push(text); }); const statusEl = el.querySelector('[class*="ScoreboardScoreCell__Time"], [class*="Status"], .game-status, [class*="ScoreCell__Time"]'); const linkEl = el.querySelector('a[href*="/game/"], a[href*="/gamecast/"], a[href*="/boxscore"]'); games.push({ teams: teams, scores: scores, status: statusEl?.textContent?.trim() || '', url: linkEl?.href || '' }); } }); return { sport: params.sport, game_count: games.length, games: games };`)

  return result
}
